"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[19168],{19168:e=>{e.exports=JSON.parse('{"color":{"name":"color","title":"Color","category":"foundations","description":"Semantic color tokens for surfaces, text, icons, borders, and status indicators.","tokenCategory":"color","sections":[{"title":"Overview","category":"foundations","content":[{"type":"prose","text":"Colors are semantic: tokens describe purpose, not appearance. Every color adapts automatically between light and dark modes via CSS light-dark(). Themes override the resolved values, so your code never references raw hex colors."}]},{"title":"Surface Colors","category":"foundations","content":[{"type":"prose","text":"Layered surface hierarchy: body → surface → card → popover. Each level sits visually above the previous one."},{"type":"prose","text":"Semantic colors for consistent theming. All colors use light-dark() for automatic mode switching."},{"type":"table","headers":["Token","Light","Dark"],"rows":[["--color-accent","#0064E0","#2694FE"],["--color-accent-muted","#0082FB33","#0082FB3F"],["--color-on-accent","#FFFFFF","#FFFFFF"],["--color-neutral","light-dark(rgba(5, 54, 89, 0.1), rgba(223, 226, 229, 0.2))","light-dark(rgba(5, 54, 89, 0.1), rgba(223, 226, 229, 0.2))"],["--color-background-surface","#FFFFFF","#1F1F22"],["--color-background-body","#F1F4F7","#111112"],["--color-overlay","#01122866","#11111299"],["--color-overlay-hover","#0536590C","#FFFFFF0C"],["--color-overlay-pressed","#05365919","#FFFFFF19"],["--color-background-muted","#0536590C","#1111127F"],["--color-text-primary","#0A1317","#DFE2E5"],["--color-text-secondary","#4E606F","#AAAFB5"],["--color-text-disabled","#A4B0BC","#6F747C"],["--color-text-accent","#0064E0","#3E9EFB"],["--color-on-dark","#FFFFFF","#FFFFFF"],["--color-on-light","#000000","#000000"],["--color-icon-accent","#0064E0","#2694FE"],["--color-icon-primary","#0A1317","#DFE2E5"],["--color-icon-secondary","#4E606F","#AAAFB5"],["--color-icon-disabled","#A4B0BC","#6F747C"],["--color-background-card","#FFFFFF","#1F1F22"],["--color-background-popover","#FFFFFF","#28292C"],["--color-background-inverted","#0A1317","#FFFFFF"],["--color-background-error-inverted","#AA071E","#E3193B"],["--color-success","#0D8626","#0D8626"],["--color-success-muted","#0B991F33","#0B991F3F"],["--color-on-success","#FFFFFF","#FFFFFF"],["--color-error","#E3193B","#F5394F"],["--color-error-muted","#E3193B33","#F5394F3F"],["--color-on-error","#FFFFFF","#FFFFFF"],["--color-warning","#E9AF08","#F2C00B"],["--color-warning-muted","#E2A40033","#E2A4003F"],["--color-on-warning","#0A1317","#0A1317"],["--color-border","#05365919","#F2F4F619"],["--color-border-emphasized","#CCD3DB","#494D53"],["--color-skeleton","#CCD3DB","#5A5E66"],["--color-track","#CCD3DB","#5A5E66"],["--color-shadow","light-dark(rgba(5, 54, 89, 0.1), rgba(0, 0, 0, 0.3))","light-dark(rgba(5, 54, 89, 0.1), rgba(0, 0, 0, 0.3))"],["--color-tint-hover","black","white"],["--color-background-blue","#0171E333","#0171E333"],["--color-border-blue","#0064E0","#2694FE"],["--color-icon-blue","#0064E0","#2694FE"],["--color-text-blue","#042F97","#AFD7FF"],["--color-background-cyan","#03A7D733","#03A7D733"],["--color-border-cyan","#089DD0","#0171A4"],["--color-icon-cyan","#00ACC1","#26C6DA"],["--color-text-cyan","#014975","#A1EEF9"],["--color-background-gray","#0A131733","#666A724C"],["--color-border-gray","#647685","#748695"],["--color-icon-gray","#4E606F","#AAAFB5"],["--color-text-gray","#0A1317","#E7EAED"],["--color-background-green","#24BB5E33","#24BB5E33"],["--color-border-green","#0D8626","#0B991F"],["--color-icon-green","#0D8626","#26A756"],["--color-text-green","#09441F","#A5F690"],["--color-background-orange","#F2790233","#F2790233"],["--color-border-orange","#EB6E00","#B34A01"],["--color-icon-orange","#E9690B","#FB8C00"],["--color-text-orange","#6B2203","#FDB876"],["--color-background-pink","#E638B333","#E638B333"],["--color-border-pink","#F351C0","#C02294"],["--color-icon-pink","#C2185B","#EC407A"],["--color-text-pink","#650053","#FEADE3"],["--color-background-purple","#7952FF33","#7952FF33"],["--color-border-purple","#9081FF","#7340FE"],["--color-icon-purple","#5B08D8","#7952FF"],["--color-text-purple","#3E0697","#B3B0FE"],["--color-background-red","#E3193B33","#E3193B33"],["--color-border-red","#E3193B","#F5394F"],["--color-icon-red","#D31130","#E3193B"],["--color-text-red","#7B0210","#FFB2B8"],["--color-background-teal","#0DB7AF33","#0DB7AF33"],["--color-border-teal","#08A3A3","#08767D"],["--color-icon-teal","#009688","#26A69A"],["--color-text-teal","#083943","#40DCCD"],["--color-background-yellow","#E2A40033","#E2A40033"],["--color-border-yellow","#C58600","#B47700"],["--color-icon-yellow","#FBC02D","#FFEE58"],["--color-text-yellow","#753F07","#FBCE03"]]}],"previewType":"swatch"},{"title":"Usage","category":"foundations","content":[{"type":"code","lang":"tsx","label":"Applying color tokens","code":"import * as stylex from \'@stylexjs/stylex\';\\nimport {colorVars} from \'@astryxdesign/core/theme/tokens.stylex\';\\n\\nconst styles = stylex.create({\\n  container: {\\n    backgroundColor: colorVars[\'--color-background-surface\'],\\n    color: colorVars[\'--color-text-primary\'],\\n    borderColor: colorVars[\'--color-border\'],\\n  },\\n  accent: {\\n    color: colorVars[\'--color-text-accent\'],\\n  },\\n});"}]},{"title":"Best Practices","category":"foundations","content":[{"type":"list","style":"do","items":["Use semantic tokens (--color-text-primary) instead of raw hex values.","Rely on the surface hierarchy (body → surface → card → popover) for layering.","Use status colors (success, error, warning) only for their semantic meaning."]},{"type":"list","style":"dont","items":["Hardcode hex values, since they won\'t adapt to dark mode or custom themes.","Mix accent colors with status colors in the same context.","Use --color-on-accent on non-accent backgrounds."]}]}]},"spacing":{"name":"spacing","title":"Spacing","category":"foundations","description":"Spacing scale tokens for padding, gap, and margin: the rhythmic foundation of design system layouts.","tokenCategory":"spacing","sections":[{"title":"Overview","category":"foundations","content":[{"type":"prose","text":"The design system uses a 4px base-unit spacing scale. Component gap props accept step values that map to these tokens. The scale provides fine-grained control at the small end (2px, 4px, 6px) and consistent rhythm at larger sizes (multiples of 4px)."}]},{"title":"Scale","category":"foundations","content":[{"type":"prose","text":"Spacing scale used for padding, gap, and margin. Component gap props map spacing steps to these tokens."},{"type":"table","headers":["Token","Value"],"rows":[["--spacing-0","0px"],["--spacing-0-5","2px"],["--spacing-1","4px"],["--spacing-1-5","6px"],["--spacing-2","8px"],["--spacing-3","12px"],["--spacing-4","16px"],["--spacing-5","20px"],["--spacing-6","24px"],["--spacing-7","28px"],["--spacing-8","32px"],["--spacing-9","36px"],["--spacing-10","40px"],["--spacing-11","44px"],["--spacing-12","48px"]]}],"previewType":"spacing-bar"},{"title":"Usage","category":"foundations","content":[{"type":"prose","text":"Most components accept a `gap` prop using step values (0 through 12). For custom layouts, use the spacing tokens directly in StyleX."},{"type":"code","lang":"tsx","label":"Spacing via component props vs StyleX","code":"// Via component props (preferred)\\n<Stack gap={4}>{/* 16px gap */}</Stack>\\n\\n// Via StyleX tokens (custom layouts)\\nimport {spacingVars} from \'@astryxdesign/core\';\\n\\nconst styles = stylex.create({\\n  custom: {\\n    padding: spacingVars[\'--spacing-4\'],\\n    gap: spacingVars[\'--spacing-3\'],\\n  },\\n});"}]},{"title":"Best Practices","category":"foundations","content":[{"type":"list","style":"do","items":["Use component gap props when available; they handle automatic spacing compensation.","Stick to the scale for consistency. If a value isn\'t on the scale, reconsider the design.","Use smaller steps (0.5–2) for tight internal spacing and larger steps (4–8) for section gaps."]},{"type":"list","style":"dont","items":["Use arbitrary pixel values outside the scale.","Mix spacing tokens with raw px/rem values in the same component."]}]}]},"typography":{"name":"typography","title":"Typography","category":"foundations","description":"Font families, geometric type scale, weight, line-height, and semantic text tokens for consistent, accessible text styling.","tokenCategory":"typography","sections":[{"title":"Overview","category":"foundations","content":[{"type":"prose","text":"Typography is built on a geometric type scale: base size \xd7 ratio^step, with 14px and 1.2 as defaults. Every text style is a semantic token that composes font size, weight, and line-height, so components express intent (heading, body, label) rather than raw values."},{"type":"prose","text":"Two layers work together: raw size tokens (--font-size-xs ... --font-size-5xl) form the geometric scale, and semantic type scale tokens (--text-heading-1-size, --text-body-leading, etc.) reference them by var(). Themes override the entire scale by adjusting base and ratio in defineTheme; all semantic tokens recompute automatically."}]},{"title":"Font Families","category":"foundations","content":[{"type":"prose","text":"Three font roles: body (UI text), heading (titles and headings), and code (monospace). By default, body and heading share the same system font stack; code uses a monospace stack. Custom themes can assign different families per role; heading inherits from body when not explicitly set."},{"type":"prose","text":"Font family stacks for body, code, and heading text."},{"type":"table","headers":["Token","Value"],"rows":[["--font-family-body","-apple-system, BlinkMacSystemFont, \\"Segoe UI\\", Roboto, Helvetica, Arial, sans-serif"],["--font-family-code","\\"SF Mono\\", Monaco, Consolas, monospace"],["--font-family-heading","-apple-system, BlinkMacSystemFont, \\"Segoe UI\\", Roboto, Helvetica, Arial, sans-serif"]]}],"previewType":"font-sample"},{"title":"Font Sizes","category":"foundations","content":[{"type":"prose","text":"Geometric scale: round(base \xd7 ratio^step), expressed in rem. The default scale is 14px \xd7 1.2, producing 12 steps from 4xs (6px) to 5xl (42px). Adjusting base and ratio in defineTheme regenerates every size token while preserving proportional relationships."},{"type":"prose","text":"Geometric type scale: round(14 \xd7 1.2^step). Base is 14px (--font-size-base)."},{"type":"table","headers":["Token","Value"],"rows":[["--font-size-4xs","0.375rem"],["--font-size-3xs","0.4375rem"],["--font-size-2xs","0.5rem"],["--font-size-xs","0.625rem"],["--font-size-sm","0.75rem"],["--font-size-base","0.875rem"],["--font-size-lg","1.0625rem"],["--font-size-xl","1.25rem"],["--font-size-2xl","1.5rem"],["--font-size-3xl","1.8125rem"],["--font-size-4xl","2.1875rem"],["--font-size-5xl","2.625rem"]]}],"previewType":"font-sample"},{"title":"Font Weights","category":"foundations","content":[{"type":"prose","text":"Four semantic weights: normal (400, body/code), medium (500, labels/data), semibold (600, headings/titles), bold (700, strong emphasis). Type scale tokens reference these by var() so themes can remap numeric values."},{"type":"prose","text":"Font weight values for body, emphasis, and headings."},{"type":"table","headers":["Token","Value"],"rows":[["--font-weight-normal","400"],["--font-weight-medium","500"],["--font-weight-semibold","600"],["--font-weight-bold","700"]]}],"previewType":"font-sample"},{"title":"Line Height","category":"foundations","content":[{"type":"prose","text":"Line heights are computed from a tiered target ratio and snapped to a 4px vertical grid. Small text (<20px) targets 1.5, medium text (20–31px) targets 1.4, and large text (≥32px) targets 1.25. A minimum gap of fontSize + 4px is enforced. The result is a unitless ratio stored in each --text-*-leading token."},{"type":"prose","text":"The 4px grid matters: every line box aligns to 4px increments, which keeps baselines, spacing, and component heights predictable. The expandTypeScale utility computes these automatically when you provide a base and ratio, so you should never need to set line-height manually."}]},{"title":"Type Scale","category":"foundations","content":[{"type":"prose","text":"Semantic tokens that combine size, weight, and line-height into a single type style. Each token triplet (--text-*-size, --text-*-weight, --text-*-leading) is consumed by Text and Heading. Use the component props rather than composing raw font tokens."},{"type":"prose","text":"Semantic tokens for headings, body, labels, code, supporting text, and display text. References font size and weight tokens. Override via typography.scale in defineTheme."},{"type":"table","headers":["Token","Value"],"rows":[["--text-heading-1-size","var(--font-size-2xl)"],["--text-heading-1-weight","var(--font-weight-semibold)"],["--text-heading-1-leading","1.3333"],["--text-heading-2-size","var(--font-size-xl)"],["--text-heading-2-weight","var(--font-weight-semibold)"],["--text-heading-2-leading","1.4"],["--text-heading-3-size","var(--font-size-lg)"],["--text-heading-3-weight","var(--font-weight-semibold)"],["--text-heading-3-leading","1.4118"],["--text-heading-4-size","var(--font-size-base)"],["--text-heading-4-weight","var(--font-weight-semibold)"],["--text-heading-4-leading","1.4286"],["--text-heading-5-size","var(--font-size-sm)"],["--text-heading-5-weight","var(--font-weight-semibold)"],["--text-heading-5-leading","1.6667"],["--text-heading-6-size","var(--font-size-xs)"],["--text-heading-6-weight","var(--font-weight-semibold)"],["--text-heading-6-leading","1.6"],["--text-body-size","var(--font-size-base)"],["--text-body-weight","var(--font-weight-normal)"],["--text-body-leading","1.4286"],["--text-large-size","var(--font-size-lg)"],["--text-large-weight","var(--font-weight-semibold)"],["--text-large-leading","1.4118"],["--text-label-size","var(--font-size-base)"],["--text-label-weight","var(--font-weight-medium)"],["--text-label-leading","1.4286"],["--text-code-size","var(--font-size-base)"],["--text-code-weight","var(--font-weight-normal)"],["--text-code-leading","1.4286"],["--text-supporting-size","var(--font-size-sm)"],["--text-supporting-weight","var(--font-weight-normal)"],["--text-supporting-leading","1.6667"],["--text-display-1-size","var(--font-size-5xl)"],["--text-display-1-weight","var(--font-weight-normal)"],["--text-display-1-leading","1.2381"],["--text-display-2-size","var(--font-size-4xl)"],["--text-display-2-weight","var(--font-weight-normal)"],["--text-display-2-leading","1.2571"],["--text-display-3-size","var(--font-size-3xl)"],["--text-display-3-weight","var(--font-weight-normal)"],["--text-display-3-leading","1.2414"]]}],"previewType":"font-sample"},{"title":"Display Text","category":"foundations","content":[{"type":"prose","text":"Display variants (display-1, display-2, display-3) continue the geometric progression above heading-1, at steps +6, +5, and +4. They use normal weight (400) instead of semibold, and tighter line-heights (~1.2), since large text reads better with less leading. Use display types for hero banners, marketing headlines, and data callouts, not for document headings."},{"type":"prose","text":"Display text often needs heading semantics for accessibility. Use the type prop on Heading to apply display styling while preserving the correct HTML element: <Heading level={1} type=\\"display-1\\"> gives you display-1 styling with an <h1> tag, so screen readers see the correct document outline."}]},{"title":"Usage","category":"foundations","content":[{"type":"code","lang":"tsx","label":"Heading for document structure","code":"import {Heading} from \'@astryxdesign/core\';\\n\\n// Heading levels map to semantic tokens: level 1 → --text-heading-1-*\\n<Heading level={1}>Page Title</Heading>\\n<Heading level={2}>Section</Heading>\\n<Heading level={3}>Subsection</Heading>\\n\\n// Display type for hero/marketing headings — level sets the HTML element\\n<Heading level={1} type=\\"display-1\\">Hero Title</Heading>\\n<Heading level={2} type=\\"display-2\\">$1.2M Revenue</Heading>\\n\\n// Override the accessibility level when visual ≠ document hierarchy\\n<Heading level={2} accessibilityLevel={3}>\\n  Sidebar Section\\n</Heading>"},{"type":"code","lang":"tsx","label":"Text for body, label, and display text","code":"import {Text} from \'@astryxdesign/core\';\\n\\n<Text type=\\"body\\">Body text at the base scale.</Text>\\n<Text type=\\"large\\">Emphasized body text.</Text>\\n<Text type=\\"label\\">Form label</Text>\\n<Text type=\\"supporting\\">Helper text, timestamps, metadata.</Text>\\n<Text type=\\"code\\">{\'const x = 1;\'}</Text>\\n\\n// Display without heading semantics (data callouts, decorative)\\n<Text type=\\"display-2\\">$1.2M Revenue</Text>"},{"type":"code","lang":"tsx","label":"Customizing the type scale via defineTheme","code":"import {defineTheme} from \'@astryxdesign/core\';\\n\\n// Adjust the entire ramp holistically with base and ratio\\nconst editorialTheme = defineTheme({\\n  name: \'editorial\',\\n  typography: {\\n    scale: { base: 16, ratio: 1.25 },          // airy / article feel\\n    body: { family: \'Geist\', fallbacks: \'-apple-system, sans-serif\' },\\n    heading: { weight: \'bold\' },\\n    code: { family: \'Geist Mono\', fallbacks: \'\\"SF Mono\\", monospace\' },\\n  },\\n});\\n\\nconst denseTheme = defineTheme({\\n  name: \'dense\',\\n  typography: {\\n    scale: { base: 12, ratio: 1.125 },          // compact / data-dense UI\\n  },\\n});"}]},{"title":"Best Practices","category":"foundations","content":[{"type":"list","style":"do","items":["Use Heading for document headings and Text for everything else; they apply the full type scale automatically.","Adjust typography holistically: change base and ratio in defineTheme to shift the entire ramp (e.g. { base: 16, ratio: 1.25 } for editorial, { base: 12, ratio: 1.125 } for dense UI).","Use display types with as=\\"h1\\" (or h2/h3) when display text is a page heading; this preserves accessibility while giving you display-level sizing. Or better, use <Heading level={1} type=\\"display-1\\"> which handles both semantics and styling.","Let line-height snap to the 4px grid via the type scale; expandTypeScale computes leading automatically from base and ratio.","Use the supporting type for secondary information: timestamps, helper text, metadata, captions.","Use accessibilityLevel on Heading when the visual hierarchy doesn\'t match the document outline (e.g. sidebar or card headings)."]},{"type":"list","style":"dont","items":["Set font-size or line-height manually; use the semantic type scale tokens so the full ramp stays consistent and 4px-grid-aligned.","Skip heading levels (e.g. h1 to h3); screen readers rely on an unbroken hierarchy. Use accessibilityLevel to decouple visual from semantic level.","Use display types for body content or in-page sections; they\'re designed for hero/marketing/data-callout contexts only.","Override individual size tokens (--font-size-lg) to \\"tweak\\" a heading; adjust base/ratio instead so proportions remain coherent across the entire scale.","Use raw numeric font-weight values (400, 600); reference the semantic weight tokens so themes can remap them."]}]}]},"elevation":{"name":"elevation","title":"Elevation","category":"foundations","description":"Shadow tokens for visual elevation and inset state rings.","tokenCategory":"shadow","sections":[{"title":"Overview","category":"foundations","content":[{"type":"prose","text":"Elevation tokens create depth through box-shadow. Three levels (low, med, high) establish a visual hierarchy for floating elements. Inset shadows provide focus and selection rings for interactive components."}]},{"title":"Elevation Scale","category":"foundations","content":[{"type":"prose","text":"Each level adds stronger offset and spread. Shadow color adapts to dark mode automatically via light-dark()."},{"type":"prose","text":"Elevation shadows (low to med to high) and inset shadows for input state rings."},{"type":"table","headers":["Token","Value"],"rows":[["--shadow-low","0px 1px 1px light-dark(rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.2)), 0px 2px 8px light-dark(rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.2))"],["--shadow-med","0px 1px 2px light-dark(rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.2)), 0px 2px 12px light-dark(rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.2))"],["--shadow-high","0px 2px 2px light-dark(rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.2)), 0px 8px 24px light-dark(rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.3))"],["--shadow-inset-hover","inset 0px 0px 0px 2px light-dark(rgba(5, 54, 89, 0.15), rgba(223, 226, 229, 0.2))"],["--shadow-inset-selected","inset 0px 0px 0px 2px rgba(1, 113, 227, 0.5)"],["--shadow-inset-success","inset 0px 0px 0px 2px rgba(38, 167, 86, 0.3)"],["--shadow-inset-warning","inset 0px 0px 0px 2px rgba(226, 164, 0, 0.3)"],["--shadow-inset-error","inset 0px 0px 0px 2px rgba(227, 25, 59, 0.3)"]]}],"previewType":"shadow-box"},{"title":"Usage","category":"foundations","content":[{"type":"code","lang":"tsx","label":"Applying elevation","code":"import {shadowVars} from \'@astryxdesign/core\';\\n\\nconst styles = stylex.create({\\n  dropdown: {\\n    boxShadow: shadowVars[\'--shadow-med\'],\\n  },\\n  dialog: {\\n    boxShadow: shadowVars[\'--shadow-high\'],\\n  },\\n  inputFocused: {\\n    boxShadow: shadowVars[\'--shadow-inset-selected\'],\\n  },\\n});"}]},{"title":"Best Practices","category":"foundations","content":[{"type":"list","style":"do","items":["Match elevation to interaction context: low for tooltips, med for dropdowns, high for dialogs.","Use inset shadows for input focus/selection states; they compose better than outlines."]},{"type":"list","style":"dont","items":["Stack multiple elevation levels on the same element.","Use elevation shadows for decorative borders. Use --color-border tokens instead."]}]}]},"shape":{"name":"shape","title":"Shape","category":"foundations","description":"Border radius tokens for consistent component rounding, from sharp corners to full pills.","tokenCategory":"radius","sections":[{"title":"Overview","category":"foundations","content":[{"type":"prose","text":"The radius scale uses a semantic naming system: inner → element → container → page. Each level fits a specific context. Themes can multiply the entire scale via a radius multiplier, with --radius-none and --radius-full as fixed anchors."}]},{"title":"Radius Scale","category":"foundations","content":[{"type":"prose","text":"Numeric scale based on a 4dp base unit. Tokens scale with the theme\'s radius multiplier; --radius-none and --radius-full are fixed."},{"type":"table","headers":["Token","Value"],"rows":[["--radius-none","0px"],["--radius-inner","4px"],["--radius-element","8px"],["--radius-container","12px"],["--radius-page","28px"],["--radius-chat","28px"],["--radius-full","9999px"]]}],"previewType":"radius-box"},{"title":"Concentric Radius","category":"foundations","content":[{"type":"prose","text":"When a rounded container has padding, inner elements need a smaller radius to appear concentric. Components like Card handle this automatically; the inner radius is computed as max(0, outerRadius - padding)."},{"type":"code","lang":"css","label":"Concentric radius formula","code":"/* Automatic in Astryx Card */\\n--card-concentric-radius: max(0px, calc(var(--_card-radius) - var(--card-padding)));"}]},{"title":"Best Practices","category":"foundations","content":[{"type":"list","style":"do","items":["Use --radius-element for interactive controls (buttons, inputs, selectors).","Use --radius-container for content containers (cards, panels, dialogs).","Use --radius-full for pill shapes (badges, tags, avatar status dots)."]},{"type":"list","style":"dont","items":["Use --radius-page for small elements; it\'s meant for page-level containers.","Hardcode radius values; they won\'t scale with theme radius multipliers."]}]}]},"motion":{"name":"motion","title":"Motion","category":"foundations","description":"Duration and easing tokens for animations and transitions.","tokenCategory":"duration","sections":[{"title":"Overview","category":"foundations","content":[{"type":"prose","text":"Motion serves two purposes: it makes interfaces easier to understand, and it makes them more pleasant to use. A panel animating open helps the eye track what changed and where new content sits in the layout. These moments reduce cognitive load and make the interface feel responsive."},{"type":"prose","text":"At the same time, well-tuned motion gives an application a sense of craft and polish that users notice, even if they can\'t name it."},{"type":"prose","text":"The design system provides duration and easing tokens that keep these moments consistent across your application."}]},{"title":"Duration","category":"foundations","content":[{"type":"prose","text":"Motion duration primitives. Three bands: fast (micro-interactions), medium (entrance/exit), slow (continuous). Min/max variants derive from base \xd7 ratio."},{"type":"table","headers":["Token","Value"],"rows":[["--duration-fast-min","130ms"],["--duration-fast","175ms"],["--duration-fast-max","230ms"],["--duration-medium-min","310ms"],["--duration-medium","410ms"],["--duration-medium-max","550ms"],["--duration-slow-min","730ms"],["--duration-slow","975ms"],["--duration-slow-max","1300ms"]]}],"previewType":"duration-bar"},{"title":"Easing","category":"foundations","content":[{"type":"prose","text":"Easing curves for animations and transitions."},{"type":"table","headers":["Token","Value"],"rows":[["--ease-standard","cubic-bezier(0.24, 1, 0.4, 1)"]]}],"previewType":"easing-curve"},{"title":"Where Motion Helps","category":"foundations","content":[{"type":"prose","text":"Some parts of the interface benefit from animation. Panels, dialogs, and collapsible sections are disorienting when they appear instantly, so animation gives the eye something to follow. Toasts and notifications need just enough entrance to be noticed without startling. State changes like a switch flipping or a selection highlighting feel more intentional with a brief transition."},{"type":"prose","text":"The common thread is that these are moments where the user needs to understand what happened."}]},{"title":"Where Motion Hurts","category":"foundations","content":[{"type":"prose","text":"Table row hovers. List item highlights. Anything the user does dozens of times per minute. Adding perceptible duration to these interactions makes the interface feel like it\'s catching up to the cursor. Keep these fast enough that the user never notices a delay."},{"type":"prose","text":"Animations that block interaction are worse. If a user has to wait for a panel to finish sliding before they can click something inside it, the animation has become an obstacle. Motion should never stand between the user and their next action."}]},{"title":"Movement Principles","category":"foundations","content":[{"type":"list","style":"unordered","items":["Not everything needs an animated exit. Elements the user is moving away from, such as tooltips, hover cards, and dropdown menus, can disappear instantly. The user has already shifted their attention. Animate the exit only when it helps orient the user, like a panel closing or a dialog dismissing to reveal what\'s underneath.","When you do animate exit, match the entrance. A panel that slides in from the right should slide back out to the right.","Direction should match the action. Navigating deeper into content should feel like moving forward. Going back should feel like returning. This keeps the user oriented in the structure of the application.","Contextual UI should feel connected to its trigger. A dropdown should expand from the button that opened it. A popover should appear near the element it describes. This doesn\'t apply to global UI like command palettes or toasts, which have their own fixed positions."]}]},{"title":"Respecting User Preferences","category":"foundations","content":[{"type":"prose","text":"Some users experience motion sensitivity; animation that feels polished to one person can cause discomfort for another. Components should honor the operating system\'s reduced motion setting. When it\'s enabled, replace animations with instant state changes."}]},{"title":"Usage","category":"foundations","content":[{"type":"code","lang":"tsx","label":"Applying motion tokens","code":"import {durationVars, easeVars} from \'@astryxdesign/core\';\\n\\nconst styles = stylex.create({\\n  fadeIn: {\\n    transitionProperty: \'opacity\',\\n    transitionDuration: durationVars[\'--duration-fast\'],\\n    transitionTimingFunction: easeVars[\'--ease-standard\'],\\n  },\\n  slideUp: {\\n    transitionProperty: \'transform, opacity\',\\n    transitionDuration: durationVars[\'--duration-medium\'],\\n    transitionTimingFunction: easeVars[\'--ease-standard\'],\\n  },\\n});"}]},{"title":"Best Practices","category":"foundations","content":[{"type":"list","style":"do","items":["Animate transitions that involve spatial change: panels opening, content expanding, elements entering the screen.","Use fast tokens for small, frequent interactions. Use medium tokens for larger transitions that rearrange the layout.","Honor reduced motion preferences at the OS level."]},{"type":"list","style":"dont","items":["Let hover states or high-frequency interactions feel like they\'re lagging behind the user.","Let animation delay when a user can interact with new content. The transition should complete before (or not block) the next action.","Move elements in ways that contradict where they came from or where they\'re going."]}]}]}}')}}]);